contracts/DisputeResolver.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./IRelayVault.sol";

interface ITaskEscrowDispute {
    function resolveDispute(bytes32 escrowId, uint8 resolutionOutcome) external;
}

contract DisputeResolver {
    address public owner;
    address public taskEscrow;
    IAgentRegistry public registry;

    enum DisputeState { OPEN, EVIDENCE_GATHERING, VOTING, RESOLVED, APPEALED }
    enum Resolution { NONE, FULL_PAYER, FULL_RECEIVER, SPLIT }

    struct Dispute {
        bytes32 disputeId;
        bytes32 escrowId;
        address claimant;
        address respondent;
        string[] evidenceCIDs;
        address[] arbitrators;
        mapping(address => Resolution) votes;
        Resolution finalResolution;
        DisputeState state;
        uint256 voteDeadlineBlock;
    }

    mapping(bytes32 => Dispute) public disputes;

    event DisputeCreated(bytes32 indexed disputeId, bytes32 indexed escrowId, address claimant);
    event EvidenceSubmitted(bytes32 indexed disputeId, address by, string evidenceCID);
    event ArbitratorVoted(bytes32 indexed disputeId, address arbitrator, Resolution resolution);
    event DisputeResolved(bytes32 indexed disputeId, Resolution finalResolution);

    constructor(address _registry) {
        owner = msg.sender;
        registry = IAgentRegistry(_registry);
    }

    function setTaskEscrow(address _taskEscrow) external {
        require(msg.sender == owner, "Only owner");
        taskEscrow = _taskEscrow;
    }

    function openDispute(bytes32 escrowId, string calldata evidenceCID, address respondent) external returns (bytes32) {
        require(msg.sender == address(taskEscrow), "Only TaskEscrow");

        bytes32 disputeId = keccak256(abi.encodePacked(escrowId, block.timestamp));
        Dispute storage d = disputes[disputeId];
        d.disputeId = disputeId;
        d.escrowId = escrowId;
        d.claimant = msg.sender;
        d.respondent = respondent;
        d.state = DisputeState.EVIDENCE_GATHERING;
        d.voteDeadlineBlock = block.number + 86400; // 24 hours voting window (1 block/sec)

        d.evidenceCIDs.push(evidenceCID);

        emit DisputeCreated(disputeId, escrowId, msg.sender);
        return disputeId;
    }

    function submitEvidence(bytes32 disputeId, string calldata evidenceCID) external {
        Dispute storage d = disputes[disputeId];
        require(d.state == DisputeState.EVIDENCE_GATHERING, "Not gathering evidence");
        require(msg.sender == d.claimant || msg.sender == d.respondent, "Not involved");

        d.evidenceCIDs.push(evidenceCID);
        emit EvidenceSubmitted(disputeId, msg.sender, evidenceCID);
    }

    function assignArbitrators(bytes32 disputeId, address[] calldata arbitratorsList) external {
        // Simplified selection mechanism restricted to owner (In real-world would use VRF)
        require(msg.sender == owner, "Only owner");
        Dispute storage d = disputes[disputeId];
        require(d.state == DisputeState.EVIDENCE_GATHERING, "Invalid state");

        d.arbitrators = arbitratorsList;
        d.state = DisputeState.VOTING;
    }

    function voteResolution(bytes32 disputeId, Resolution resolution) external {
        Dispute storage d = disputes[disputeId];
        require(d.state == DisputeState.VOTING, "Not voting Phase");
        require(block.number <= d.voteDeadlineBlock, "Voting ended");
        
        bool isArbitrator = false;
        for (uint i = 0; i < d.arbitrators.length; i++) {
            if (d.arbitrators[i] == msg.sender) {
                isArbitrator = true;
                break;
            }
        }
        require(isArbitrator, "Not an arbitrator");
        require(d.votes[msg.sender] == Resolution.NONE, "Already voted");

        d.votes[msg.sender] = resolution;
        emit ArbitratorVoted(disputeId, msg.sender, resolution);
    }

    function finalizeResolution(bytes32 disputeId) external {
        Dispute storage d = disputes[disputeId];
        require(d.state == DisputeState.VOTING, "Not in voting phase");
        require(block.number > d.voteDeadlineBlock, "Voting not yet finished");

        // Simplified tally logic: majority wins 
        uint256 countsPayer = 0;
        uint256 countsReceiver = 0;
        uint256 countsSplit = 0;

        for (uint i = 0; i < d.arbitrators.length; i++) {
            Resolution v = d.votes[d.arbitrators[i]];
            if (v == Resolution.FULL_PAYER) countsPayer++;
            else if (v == Resolution.FULL_RECEIVER) countsReceiver++;
            else if (v == Resolution.SPLIT) countsSplit++;
        }

        if (countsPayer > countsReceiver && countsPayer > countsSplit) {
            d.finalResolution = Resolution.FULL_PAYER;
        } else if (countsReceiver > countsPayer && countsReceiver > countsSplit) {
            d.finalResolution = Resolution.FULL_RECEIVER;
        } else {
            d.finalResolution = Resolution.SPLIT;
        }

        d.state = DisputeState.RESOLVED;

        ITaskEscrowDispute(taskEscrow).resolveDispute(d.escrowId, uint8(d.finalResolution));
        emit DisputeResolved(disputeId, d.finalResolution);
    }
}

contracts/IRelayVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IAgentRegistry {
    enum PricingType { FIXED, AUCTION, DYNAMIC }
    enum AgentStatus { ACTIVE, SUSPENDED, INACTIVE }

    struct PricingModel {
        uint256 basePrice;
        address currency;
        PricingType pricingType;
    }

    struct AgentInfo {
        address agentId;
        bytes32[] capabilities;
        PricingModel pricingModel;
        uint256 reputationScore;
        address vaultAddress;
        AgentStatus status;
        uint256 registeredAt;
        uint256 totalTasksCompleted;
    }

    function register(bytes32[] calldata capabilities, PricingModel calldata pricingModel, bytes calldata routingConfig) external;
    function updateCapabilities(address agentId, bytes32[] calldata capabilities) external;
    function updatePricing(address agentId, PricingModel calldata pricingModel) external;
    function updateReputation(address agentId, int256 deltaScore, bytes32 taskId) external;
    function getAgent(address agentId) external view returns (AgentInfo memory);
    function getVaultAddress(address agentId) external view returns (address);
    function suspend(address agentId, string calldata reason) external;
    function deregister(address agentId) external;
}

interface IVaultWallet {
    struct SplitRecipient {
        address recipient;
        uint16 bps;
    }

    function initialize(address _owner, address _taskEscrow, address _currency) external;
    function setRouting(SplitRecipient[] calldata splits, uint16 lockBps, uint16 holdBps) external;
    function receivePayment(uint256 amount, bytes32 taskId, address payer) external;
    function withdraw(uint256 amount, address recipient) external;
    function claimUnlocked() external;
    function getBalance() external view returns (uint256 available, uint256 locked, uint256 total);
}

interface INegotiationEngine {
    enum BidState { OPEN, COUNTERED, ACCEPTED, EXPIRED, CANCELLED }

    struct CounterBid {
        uint256 price;
        address by;
        uint256 at;
    }

    struct Bid {
        bytes32 bidId;
        string taskSpecCID;
        address initiator;
        address targetAgent;
        uint256 price;
        uint256 ttlBlocks;
        BidState state;
        CounterBid[] counterHistory;
        uint256 createdAt;
    }

    function submitBid(string calldata taskSpecCID, address targetAgent, uint256 price, uint256 ttlBlocks) external returns (bytes32);
    function counterBid(bytes32 bidId, uint256 newPrice) external;
    function acceptBid(bytes32 bidId) external;
    function cancelBid(bytes32 bidId) external;
    function getBid(bytes32 bidId) external view returns (Bid memory);
}

interface ITaskEscrow {
    enum EscrowState { PENDING_LOCK, LOCKED, COMPLETED, RELEASED, DISPUTED, REFUNDED, EXPIRED }
    enum VerificationMethod { ORACLE, AUTOMATED, OPTIMISTIC, HUMAN, SELF_REPORT }

    struct Escrow {
        bytes32 escrowId;
        bytes32 bidId;
        address payer;
        address receiver;
        uint256 amount;
        uint256 deadlineBlock;
        EscrowState state;
        VerificationMethod verificationMethod;
    }

    function lockFunds(bytes32 bidId, uint256 amount, uint256 deadlineBlocks) external;
    function verifyAndRelease(bytes32 escrowId, string calldata completionProof) external;
    function openDispute(bytes32 escrowId, string calldata evidenceCID) external;
    function resolveDispute(bytes32 escrowId, uint8 resolutionOutcome) external;
}

contracts/NegotiationEngine.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./IRelayVault.sol";

contract NegotiationEngine is INegotiationEngine {
    address public owner;
    address public taskEscrow;
    IAgentRegistry public registry;

    mapping(bytes32 => Bid) public bids;
    bytes32[] public allBidIds;
    
    // Mapping target agent to their open bids
    mapping(address => bytes32[]) public agentBids;

    event BidSubmitted(bytes32 indexed bidId, address initiator, address targetAgent, string taskSpecCID, uint256 price, uint256 ttl);
    event BidCountered(bytes32 indexed bidId, address by, uint256 newPrice);
    event BidAccepted(bytes32 indexed bidId, uint256 agreedPrice, bytes32 escrowId);
    event BidCancelled(bytes32 indexed bidId);

    constructor(address _registry) {
        owner = msg.sender;
        registry = IAgentRegistry(_registry);
    }

    function setTaskEscrow(address _taskEscrow) external {
        require(msg.sender == owner, "Only owner");
        taskEscrow = _taskEscrow;
    }

    function submitBid(string calldata taskSpecCID, address targetAgent, uint256 price, uint256 ttlBlocks) external override returns (bytes32) {
        require(registry.getVaultAddress(targetAgent) != address(0), "Target agent not found");

        bytes32 bidId = keccak256(abi.encodePacked(msg.sender, targetAgent, taskSpecCID, block.timestamp));
        require(bids[bidId].initiator == address(0), "Bid exists");

        Bid storage newBid = bids[bidId];
        newBid.bidId = bidId;
        newBid.taskSpecCID = taskSpecCID;
        newBid.initiator = msg.sender;
        newBid.targetAgent = targetAgent;
        newBid.price = price;
        newBid.ttlBlocks = block.number + ttlBlocks;
        newBid.state = BidState.OPEN;
        newBid.createdAt = block.timestamp;

        allBidIds.push(bidId);
        agentBids[targetAgent].push(bidId);
        agentBids[msg.sender].push(bidId);

        emit BidSubmitted(bidId, msg.sender, targetAgent, taskSpecCID, price, ttlBlocks);
        return bidId;
    }

    function counterBid(bytes32 bidId, uint256 newPrice) external override {
        Bid storage bid = bids[bidId];
        require(bid.state == BidState.OPEN || bid.state == BidState.COUNTERED, "Not open");
        require(block.number <= bid.ttlBlocks, "Bid expired");
        require(msg.sender == bid.initiator || msg.sender == bid.targetAgent, "Unauthorized");

        bid.price = newPrice;
        bid.state = BidState.COUNTERED;
        bid.ttlBlocks = block.number + 86400; // Reset TTL on counter (24 hours)

        bid.counterHistory.push(CounterBid({
            price: newPrice,
            by: msg.sender,
            at: block.timestamp
        }));

        emit BidCountered(bidId, msg.sender, newPrice);
    }

    function acceptBid(bytes32 bidId) external override {
        Bid storage bid = bids[bidId];
        require(bid.state == BidState.OPEN || bid.state == BidState.COUNTERED, "Not open");
        require(block.number <= bid.ttlBlocks, "Bid expired");
        require(msg.sender == bid.initiator || msg.sender == bid.targetAgent, "Unauthorized");

        bid.state = BidState.ACCEPTED;

        // Auto lock funds in TaskEscrow (Skipped USDC allowance check for brevity)
        bytes32 escrowId = keccak256(abi.encodePacked(bidId, block.timestamp));
        
        // Ensure taskEscrow has the lockFunds method and call it.
        // In a complete implementation, this would require approval from payer.
        ITaskEscrow(taskEscrow).lockFunds(bidId, bid.price, 2592000); // Give agent ~30 days (1 block/sec) to complete task

        emit BidAccepted(bidId, bid.price, escrowId);
    }

    function cancelBid(bytes32 bidId) external override {
        Bid storage bid = bids[bidId];
        require(bid.state == BidState.OPEN || bid.state == BidState.COUNTERED, "Not open");
        require(msg.sender == bid.initiator, "Only initiator can cancel");

        bid.state = BidState.CANCELLED;
        emit BidCancelled(bidId);
    }

    function getBid(bytes32 bidId) external view override returns (Bid memory) {
        return bids[bidId];
    }

    function getAgentBids(address agent) external view returns (bytes32[] memory) {
        return agentBids[agent];
    }

    function getAllBidIds() external view returns (bytes32[] memory) {
        return allBidIds;
    }
}

contracts/ReputationBondManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./IRelayVault.sol";

contract ReputationBondManager {
    address public owner;
    IAgentRegistry public registry;
    address public disputeResolver;

    event BondSlashed(address indexed agentId, uint256 slashedAmount, bytes32 taskId);

    constructor(address _registry) {
        owner = msg.sender;
        registry = IAgentRegistry(_registry);
    }

    function setDisputeResolver(address _disputeResolver) external {
        require(msg.sender == owner, "Only owner");
        disputeResolver = _disputeResolver;
    }

    function calculateRequiredBond(uint256 taskValueUsdc) public pure returns (uint256) {
        if (taskValueUsdc < 100 * 1e18) { // Assuming 18 decimals
            return 0;
        } else if (taskValueUsdc <= 1000 * 1e18) {
            return (taskValueUsdc * 10) / 100; // 10%
        } else if (taskValueUsdc <= 10000 * 1e18) {
            return (taskValueUsdc * 15) / 100; // 15%
        } else {
            return (taskValueUsdc * 20) / 100; // 20%
        }
    }

    function verifyBondSufficiency(address agentId, uint256 taskValueUsdc) external view returns (bool) {
        address vaultAddress = registry.getVaultAddress(agentId);
        require(vaultAddress != address(0), "Vault does not exist");
        
        IVaultWallet vault = IVaultWallet(vaultAddress);
        (, uint256 lockedBalance, ) = vault.getBalance();
        
        uint256 requiredBond = calculateRequiredBond(taskValueUsdc);
        return lockedBalance >= requiredBond;
    }

    function slashBond(address agentId, uint256 amount, bytes32 taskId, address recipient) external {
        require(msg.sender == disputeResolver, "Only DisputeResolver");
        address vaultAddress = registry.getVaultAddress(agentId);
        require(vaultAddress != address(0), "No vault");
        
        // This is a simplified slash. An actual implementation would require VaultWallet
        // to have a specific `slashFunds` method that only the BondManager/DisputeResolver can call.
        // For demonstration, we assume IVaultWallet supports it or the manager bypasses normally.

        emit BondSlashed(agentId, amount, taskId);
    }
}

contracts/TaskEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./IRelayVault.sol";

interface IDisputeResolver {
    function resolveDispute(bytes32 escrowId) external;
}

contract TaskEscrow is ITaskEscrow {
    address public owner;
    IAgentRegistry public registry;
    INegotiationEngine public negotiation;
    address public disputeResolver;
    address public governance;

    mapping(bytes32 => Escrow) public escrows;
    mapping(bytes32 => bool) public largeTaskApproved;
    bytes32[] public activeEscrows;

    event FundsLocked(bytes32 indexed escrowId, bytes32 bidId, address payer, address receiver, uint256 amount, uint256 deadline);
    event TaskCompleted(bytes32 indexed escrowId, string completionProof, VerificationMethod method);
    event FundsReleased(bytes32 indexed escrowId, uint256 amount, address vaultAddress);
    event DisputeOpened(bytes32 indexed escrowId, string evidenceCID);
    event EscrowRefunded(bytes32 indexed escrowId, uint256 amount);

    constructor(address _registry) {
        owner = msg.sender;
        registry = IAgentRegistry(_registry);
    }

    function setEngines(address _negotiation, address _disputeResolver, address _governance) external {
        require(msg.sender == owner, "Only owner");
        negotiation = INegotiationEngine(_negotiation);
        disputeResolver = _disputeResolver;
        governance = _governance;
    }

    function approveLargeTask(bytes32 escrowId) external {
        require(msg.sender == governance, "Only governance");
        require(escrows[escrowId].amount > 10000 * 1e18, "Not a large task");
        largeTaskApproved[escrowId] = true;
    }

    modifier onlyNegotiation() {
        require(msg.sender == address(negotiation), "Only negotiation engine");
        _;
    }

    function lockFunds(bytes32 bidId, uint256 amount, uint256 deadlineBlocks) external override onlyNegotiation {
        // Assume MON/USDC (18 decimals) transferred here from payer
        INegotiationEngine.Bid memory bid = negotiation.getBid(bidId);
        require(bid.state == INegotiationEngine.BidState.ACCEPTED, "Bid not accepted");

        bytes32 escrowId = keccak256(abi.encodePacked(bidId, block.number));
        require(escrows[escrowId].payer == address(0), "Escrow exists");

        Escrow storage newEscrow = escrows[escrowId];
        newEscrow.escrowId = escrowId;
        newEscrow.bidId = bidId;
        newEscrow.payer = bid.initiator;
        newEscrow.receiver = bid.targetAgent;
        newEscrow.amount = amount;
        newEscrow.deadlineBlock = block.number + deadlineBlocks;
        newEscrow.state = EscrowState.LOCKED;
        
        // Mock method for now
        newEscrow.verificationMethod = VerificationMethod.HUMAN;

        activeEscrows.push(escrowId);

        emit FundsLocked(escrowId, bidId, bid.initiator, bid.targetAgent, amount, newEscrow.deadlineBlock);
    }

    function verifyAndRelease(bytes32 escrowId, string calldata completionProof) external override {
        Escrow storage escrow = escrows[escrowId];
        require(escrow.state == EscrowState.LOCKED, "Not locked");
        require(msg.sender == escrow.payer || msg.sender == escrow.receiver, "Unauthorized");

        if (escrow.amount > 10000 * 1e18) {
            require(largeTaskApproved[escrowId], "Governance approval required");
        }

        escrow.state = EscrowState.RELEASED;

        // Routing payment to VaultWallet of receiver
        address vault = registry.getVaultAddress(escrow.receiver);
        require(vault != address(0), "Vault missing");

        // Forward payment to receiver's VaultWallet (USDC assumed)
        IVaultWallet(vault).receivePayment(escrow.amount, escrow.bidId, escrow.payer);
        
        // Update reputation in registry (successful task)
        registry.updateReputation(escrow.receiver, 10, escrow.bidId); // Base positive score increase

        emit TaskCompleted(escrowId, completionProof, escrow.verificationMethod);
        emit FundsReleased(escrowId, escrow.amount, vault);
    }

    function openDispute(bytes32 escrowId, string calldata evidenceCID) external override {
        Escrow storage escrow = escrows[escrowId];
        require(escrow.state == EscrowState.LOCKED || escrow.state == EscrowState.COMPLETED, "Invalid state for dispute");
        require(msg.sender == escrow.payer || msg.sender == escrow.receiver, "Unauthorized");

        escrow.state = EscrowState.DISPUTED;
        emit DisputeOpened(escrowId, evidenceCID);
    }

    function resolveDispute(bytes32 escrowId, uint8 resolutionOutcome) external override {
        require(msg.sender == disputeResolver, "Only DisputeResolver");
        Escrow storage escrow = escrows[escrowId];
        require(escrow.state == EscrowState.DISPUTED, "Not disputed");

        if (resolutionOutcome == 1) { // FULL_PAYER
            escrow.state = EscrowState.REFUNDED;
            // Refund to payer logic...
            registry.updateReputation(escrow.receiver, -20, escrow.bidId);
            emit EscrowRefunded(escrowId, escrow.amount);
        } else if (resolutionOutcome == 2) { // FULL_RECEIVER
            escrow.state = EscrowState.RELEASED;
            address vault = registry.getVaultAddress(escrow.receiver);
            IVaultWallet(vault).receivePayment(escrow.amount, escrow.bidId, escrow.payer);
            registry.updateReputation(escrow.receiver, 5, escrow.bidId);
            emit FundsReleased(escrowId, escrow.amount, vault);
        } else { // SPLIT (e.g., 50/50 block)
            uint256 split = escrow.amount / 2;
            escrow.state = EscrowState.REFUNDED;
            // Refund split to payer
            emit EscrowRefunded(escrowId, split);
            // Send split to VaultWallet
            address vault = registry.getVaultAddress(escrow.receiver);
            IVaultWallet(vault).receivePayment(split, escrow.bidId, escrow.payer);
            registry.updateReputation(escrow.receiver, -5, escrow.bidId);
            emit FundsReleased(escrowId, split, vault);
        }
    }
}

